<span class="line"><span style="--shiki-light:#FF8F40;--shiki-dark:#FF8F40;">    for</span><span style="--shiki-light:#BFBDB6;--shiki-dark:#BFBDB6;"> (i </span><span style="--shiki-light:#F29668;--shiki-dark:#F29668;">=</span><span style="--shiki-light:#D2A6FF;--shiki-dark:#D2A6FF;"> 0</span><span style="--shiki-light:#BFBDB6B3;--shiki-dark:#BFBDB6B3;">;</span><span style="--shiki-light:#BFBDB6;--shiki-dark:#BFBDB6;"> i </span><span style="--shiki-light:#F29668;--shiki-dark:#F29668;">&lt;</span><span style="--shiki-light:#BFBDB6;--shiki-dark:#BFBDB6;"> n </span><span style="--shiki-light:#F29668;--shiki-dark:#F29668;">-</span><span style="--shiki-light:#D2A6FF;--shiki-dark:#D2A6FF;"> 1</span><span style="--shiki-light:#BFBDB6B3;--shiki-dark:#BFBDB6B3;">;</span><span style="--shiki-light:#BFBDB6;--shiki-dark:#BFBDB6;"> i</span><span style="--shiki-light:#F29668;--shiki-dark:#F29668;">++</span><span style="--shiki-light:#BFBDB6;--shiki-dark:#BFBDB6;">)</span></span>
